Compiler.javapublic class Compiler &#123;

    &#x2F;&#x2F; declare constants
    private static final String TAG &#x3D; Compiler.class.getName();

    &#x2F;&#x2F; declare variables
    private static String url &#x3D; &quot;https:&#x2F;&#x2F;api.codex.jaagrav.in&quot;;

    private static HashMap&lt;String, Object&gt; map &#x3D; new HashMap&lt;&gt;();
    private static HashMap&lt;String, Object&gt; data &#x3D; new HashMap&lt;&gt;();

    private static RequestNetwork requestNetwork;
    private static RequestNetwork.RequestListener requestListener;

    private static ModernDialog.Builder dialog;
    private static AlertDialog progressDialog;

    public static void init(Activity activity) &#123;
        requestNetwork &#x3D; new RequestNetwork(activity);

        RequestListener requestListener &#x3D; new RequestNetwork.RequestListener() &#123;
            @Override
            public void onResponse(String tag, String response, HashMap&lt;String, Object&gt; responseHeaders) &#123;
                progressDialog.dismiss();

                &#x2F;&#x2F; get the output and print it to Logcat
                data &#x3D; new Gson().fromJson(response, new TypeToken&lt;HashMap&lt;String, Object&gt;&gt;()&#123;&#125;.getType());
                Log.d(TAG, data);

                &#x2F;&#x2F; compilation success
                if (data.get(&quot;error&quot;).toString().equals(&quot;&quot;)) &#123;
                    dialog.setTitle(&quot;Compilation output&quot;);
                    dialog.setMessage(data.get(&quot;output&quot;).toString());
                &#125;

                &#x2F;&#x2F; compilation failed
                else &#123;
                    dialog.setTitle(&quot;Compilation error&quot;);
                    dialog.setMessage(data.get(&quot;error&quot;).toString());
                &#125;

                &#x2F;&#x2F; display the dialog
                dialog.show();

            &#125;

            @Override
            public void onErrorResponse(String tag, String message) &#123;
                progressDialog.dismiss();

                &#x2F;&#x2F; check if no internet connection
                dialog.setTitle(&quot;No Internet&quot;);
                dialog.setMessage(message);
            &#125;
        &#125;;
    &#125;

    public static void compile(Activity activity, String code, String lang, String input) &#123;

        &#x2F;&#x2F; configuration
        map &#x3D; new HashMap&lt;&gt;();
        map.put(&quot;code&quot;, text);
        map.put(&quot;language&quot;, lang);
        map.put(&quot;input&quot;, input);
        requestNetwork.setParams(map, RequestNetworkController.REQUEST_BODY);
        requestNetwork.startRequestNetwork(RequestNetworkController.POST, url, &quot;api&quot;, requestListener);

        &#x2F;&#x2F; progress dialog
        View view &#x3D; activity.getLayoutInflater().inflate(R.layout.dialog_progress, null);
        TextView tv &#x3D; view.findViewById(R.id.tvText);
        tv.setText(&quot;Compiling, please wait ...&quot;);
