Apply ThemesHere, I will detect light theme and dark theme, the key is to use ThemeRegistry.getInstance().setTheme() to apply themes.
int mode &#x3D; getResources().getConfiguration().uiMode &amp; Configuration.UI_MODE_NIGHT_MASK;
switch (mode) &#123;
    case Configuration.UI_MODE_NIGHT_YES: &#x2F;&#x2F; dark mode
        ThemeRegistry.getInstance().setTheme(&quot;darcula&quot;);
        break;

    case Configuration.UI_MODE_NIGHT_NO: &#x2F;&#x2F; light mode
